package com.indianservers.aiexplorer.physics.ncert.assessment
import com.indianservers.aiexplorer.phase3.assessment.*
import com.indianservers.aiexplorer.learningintelligence.model.*
object PhysicsAssessmentAdapter:SubjectCriterionValidator{private val units=ScientificUnitEngine();override fun validate(criterion:StepCriterion,attempt:CriterionAttempt,prior:Map<String,CriterionScore>):CriterionValidation=when(criterion.validatorId){"mechanics-formula"->CriterionValidation(attempt.answer.replace(" ","") in setOf("F=ma","a=F/m"),feedback="Select Newton's second-law relationship.");"mechanics-value"->{val parts=attempt.answer.trim().split(Regex("\\s+"));val r=units.validate(2.0,"m",parts.firstOrNull().orEmpty(),parts.getOrElse(1){""},2,0.0..1000.0);CriterionValidation(r.numericCorrectness==1.0&&r.dimensionalCorrectness,r.numericCorrectness==1.0,r.physicallyPlausible,r.feedback.joinToString(),"2.0 m")};else->CriterionValidation(attempt.answer.isNotBlank(),feedback="Physics response checked by its subject adapter.")}}
